import java.util.ArrayList;
import java.util.List;

public List<Integer> solve(int[] nums1, int[] nums2, int[][] queries) {
    List<Integer> res = new ArrayList<>();
    for (int[] q : queries) {
        if (q[0] == 1) {
            for (int i = q[1]; i <= q[2]; i++) {
                nums1[i] ^= 1;
            }
        } else if (q[0] == 2) {
            for (int i = 0; i < nums1.length; i++) {
                nums2[i] += nums1[i] * q[1];
            }
        } else if (q[0] == 3) {
            int sum = 0;
            for (int num : nums2) {
                sum += num;
            }
            res.add(sum);
        }
    }
    return res;
}
